 45→    ("echo", "UART echo (type to see characters)", r#"// UART echo — type in the terminal, characters echo back
 46→// Demonstrates: interrupt-driven UART RX, polling UART TX
 47→// Uses __attribute__((interrupt)) for the ISR
 48→
 49→#define UART_DATA   0xFF0100
 50→#define UART_STATUS 0xFF0101
 51→#define INT_ENABLE  0xFF0010
 52→
 53→void putc(int c) {
 54→    while (*(char *)UART_STATUS & 0x80) {}
 55→    *(char *)UART_DATA = c;
 56→}
 57→
 58→// ISR: called on each UART RX byte
 59→__attribute__((interrupt))
 60→void uart_isr() {
 61→    int c = *(char *)UART_DATA;  // read & acknowledge
 62→    putc(c);                      // echo back
 63→    if (c == 13 || c == 10) {
 64→        putc(62);  // '>'
 65→        putc(32);  // ' '
 66→    }
 67→}
 68→
 69→int main() {
 70→    // Set interrupt vector
 71→    asm("la r0,_uart_isr\nmov iv,r0");
 72→    // Enable UART RX interrupt
 73→    *(char *)INT_ENABLE = 1;
 74→
 75→    putc(62); // '>'
 76→    putc(32); // ' '
 77→
 78→    // Spin forever (ISR handles input)
 79→    while (1) {}
 80→}
 81→"#),
 82→
 83→    ("led-switch", "LED follows switch S2", r#"// LED follows switch — press S2 to light LED D2
 84→// Demonstrates: polling switch input, controlling LED output
 85→// Click the S2 button below to toggle!
 86→
 87→#define LED_REG  0xFF0000
 88→
 89→int main() {
 90→    while (1) {
 91→        int sw = *(char *)LED_REG;
 92→        // Switch is bit 0: 1=released, 0=pressed
 93→        // LED is active-low: write 0=on, 1=off
 94→        // So just write the switch state to LED — pressed=0=LED on
 95→        *(char *)LED_REG = sw & 1;
 96→    }
 97→}
 98→"#),
 99→
100→    ("counter", "Live counter on UART", r#"// Live counter — prints incrementing numbers
101→// Demonstrates: busy-wait loop, UART output
102→
103→#include <stdio.h>
104→
105→void delay() {
106→    int i = 0;
107→    while (i < 5000) { i++; }
108→}
109→
110→int main() {
111→    int n = 0;
112→    while (1) {
113→        printf("%d\n", n);
114→        n++;
115→        delay();
116→    }
117→}
118→"#),
119→
120→    ("adder", "Interactive adder (type two numbers)", r#"// Interactive adder — type two numbers separated by Enter
121→// Demonstrates: UART input parsing, printf output
122→
123→#include <stdio.h>
124→
125→int getc_poll() {
126→    while (!(*(char *)0xFF0101 & 0x01)) {}
127→    return *(char *)0xFF0100;
128→}
129→
130→int read_int() {
131→    int n = 0;
132→    int started = 0;
133→    while (1) {
134→        int c = getc_poll();
135→        putchar(c);  // echo
136→        if (c >= 48 && c <= 57) {
137→            n = n * 10 + (c - 48);
138→            started = 1;
139→        } else if (started) {
140→            return n;
141→        }
142→    }
143→}
144→
145→int main() {
146→    while (1) {
147→        printf("a? ");
148→        int a = read_int();
149→        printf("b? ");
150→        int b = read_int();
151→        printf("= %d\n", a + b);
152→    }
153→}
154→"#),
155→];
