221→    // Emulator display state (updated each tick)
222→    let uart_output = use_state(String::new);
223→    let registers = use_state(|| [0u32; 8]);
224→    let pc_val = use_state(|| 0u32);
225→    let cond_flag = use_state(|| false);
226→    let led_state = use_state(|| 0u8);
227→    let running = use_state(|| false);
228→    let halted = use_state(|| false);
229→    let instr_count = use_state(|| 0u64);
230→    let status_msg = use_state(|| String::from("Ready"));
231→    let runtime_error_line = use_state(|| None::<usize>);
232→
233→    // Switch S2
234→    let switch_pressed = use_state(|| false);
235→
236→    // UART input buffer (keyboard → emulator, drained in run loop)
237→    let uart_input: Rc<RefCell<std::collections::VecDeque<u8>>> =
238→        use_mut_ref(std::collections::VecDeque::new);
239→
240→    // Interval handle
241→    let interval_handle = use_mut_ref(|| None::<gloo_timers::callback::Interval>);
242→
243→    // Loading demo
244→    let loading = use_state(|| false);
245→
246→    // --- Callbacks ---
247→
248→    let on_source_change = {
249→        let source = source.clone();
250→        Callback::from(move |value: String| source.set(value))
251→    };
252→
253→    let on_run = {
254→        let source = source.clone();
255→        let listing = listing.clone();
256→        let compile_error = compile_error.clone();
257→        let emu = emu.clone();
258→        let uart_input = uart_input.clone();
259→        let uart_output = uart_output.clone();
260→        let registers = registers.clone();
261→        let pc_val = pc_val.clone();
262→        let cond_flag = cond_flag.clone();
263→        let led_state = led_state.clone();
264→        let running = running.clone();
265→        let halted = halted.clone();
266→        let instr_count = instr_count.clone();
267→        let status_msg = status_msg.clone();
268→        let runtime_error_line = runtime_error_line.clone();
269→        let interval_handle = interval_handle.clone();
270→        let switch_pressed = switch_pressed.clone();
271→
272→        Callback::from(move |_: MouseEvent| {
273→            // Stop any existing run loop
274→            *interval_handle.borrow_mut() = None;
275→
276→            // Compile
277→            let output = compiler::compile(&source);
278→            listing.set(output.listing.clone());
279→            runtime_error_line.set(None);
280→
281→            if let Some(err) = output.error {
282→                compile_error.set(Some(err));
283→                running.set(false);
284→                halted.set(false);
285→                status_msg.set("Compile error".into());
286→                return;
287→            }
288→            compile_error.set(None);
289→
290→            // Reset emulator and load binary
291→            {
292→                let mut e = emu.borrow_mut();
293→                *e = EmulatorCore::new();
294→                e.load_program(0, &output.bytes);
295→                e.load_program_extent(output.bytes.len() as u32);
296→                e.set_button_pressed(*switch_pressed);
297→                e.resume();
298→            }
299→
300→            // Reset display state
301→            uart_output.set(String::new());
302→            registers.set([0u32; 8]);
303→            pc_val.set(0);
304→            cond_flag.set(false);
305→            led_state.set(0);
306→            halted.set(false);
307→            instr_count.set(0);
308→            status_msg.set("Running".into());
309→            running.set(true);
310→
311→            // Clear input buffer
312→            uart_input.borrow_mut().clear();
313→
314→            // Start run loop
315→            let emu = emu.clone();
316→            let uart_input = uart_input.clone();
317→            let uart_output = uart_output.clone();
318→            let registers = registers.clone();
319→            let pc_val = pc_val.clone();
320→            let cond_flag = cond_flag.clone();
321→            let led_state = led_state.clone();
322→            let running = running.clone();
323→            let halted = halted.clone();
324→            let instr_count = instr_count.clone();
325→            let status_msg = status_msg.clone();
326→            let runtime_error_line = runtime_error_line.clone();
327→            let listing = listing.clone();
328→            let interval_handle2 = interval_handle.clone();
329→
330→            let interval = gloo_timers::callback::Interval::new(16, move || {
331→                let mut e = emu.borrow_mut();
332→
333→                // Drain keyboard input buffer into UART RX when free
334→                {
335→                    let mut buf = uart_input.borrow_mut();
336→                    if !buf.is_empty()
337→                        && (e.read_byte(0xFF0101) & 0x01 == 0)
338→                        && let Some(byte) = buf.pop_front()
339→                    {
