341→                    }
342→                }
343→
344→                let batch = e.run_batch(10_000);
345→
346→                // Update display state
347→                uart_output.set(e.get_uart_output().to_string());
348→                let mut regs = [0u32; 8];
349→                for (i, reg) in regs.iter_mut().enumerate() {
350→                    *reg = e.get_reg(i as u8);
