352→                registers.set(regs);
353→                pc_val.set(e.pc());
354→                cond_flag.set(e.condition_flag());
355→                led_state.set(e.get_led());
356→                instr_count.set(e.instructions_count());
357→
358→                let stop = match batch.reason {
359→                    cor24_emulator::StopReason::Halted => {
360→                        halted.set(true);
361→                        status_msg.set("Halted".into());
362→                        true
363→                    }
364→                    cor24_emulator::StopReason::InvalidInstruction(op) => {
365→                        let pc = e.pc();
