367→                        runtime_error_line.set(line);
368→                        halted.set(true);
369→                        status_msg.set(format!("Invalid instruction: {op:#04x} at PC={pc:#06x}"));
370→                        true
371→                    }
372→                    cor24_emulator::StopReason::Paused => {
373→                        status_msg.set("Paused".into());
374→                        true
375→                    }
376→                    _ => false,
377→                };
378→
379→                if stop {
380→                    running.set(false);
381→                    *interval_handle2.borrow_mut() = None;
382→                }
383→            });
384→
385→            *interval_handle.borrow_mut() = Some(interval);
386→        })
387→    };
