733→fn render_listing(listing: &[AssembledLine], error_line: Option<usize>) -> Html {
734→    if listing.is_empty() {
735→        return html! {
736→            <pre style="flex:1; background:#181825; color:#f9e2af; border:1px solid #313244; \
737→                        border-radius:6px; padding:12px; font-family:monospace; font-size:14px; \
738→                        overflow:auto; white-space:pre;" />
739→        };
740→    }
741→
742→    fn format_listing_line(line: &AssembledLine) -> String {
743→        if line.bytes.is_empty() {
744→            format!("{:>22}{}", "", line.source)
745→        } else {
746→            let hex: String = line.bytes.iter().map(|b| format!("{b:02x} ")).collect();
747→            format!("{:06x}  {:<14}{}", line.address, hex.trim_end(), line.source)
748→        }
749→    }
750→
751→    let width = listing.len().to_string().len();
752→
753→    html! {
754→        <div style="flex:1; display:flex; background:#181825; border:1px solid #313244; \
755→                    border-radius:6px; overflow:auto; font-family:monospace; font-size:13px; \
756→                    line-height:1.5;">
757→            <pre style="margin:0; padding:12px 8px 12px 0; text-align:right; color:#bac2de; \
758→                        user-select:none; background:#11111b; border-right:1px solid #313244; \
759→                        white-space:pre;">
760→                { for listing.iter().enumerate().map(|(i, _)| {
761→                    let n = i + 1;
762→                    let is_err = error_line == Some(n);
763→                    let style = if is_err { "color:#f38ba8; background:rgba(243,139,168,0.15);" } else { "" };
764→                    html! { <span {style}>{format!("{:>width$}\n", n)}</span> }
765→                }) }
766→            </pre>
767→            <pre style="margin:0; padding:12px; white-space:pre; flex:1;">
768→                { for listing.iter().enumerate().map(|(i, line)| {
769→                    let n = i + 1;
770→                    let is_err = error_line == Some(n);
771→                    let bg = if is_err { "background:rgba(243,139,168,0.15);" } else { "" };
772→                    let formatted = format_listing_line(line);
773→                    if line.bytes.is_empty() {
774→                        html! { <div style={format!("color:#f9e2af;{bg}")}>{formatted}</div> }
775→                    } else {
776→                        let addr_end = 6;
777→                        let hex_start = 8;
778→                        let hex_end = hex_start + 14;
779→                        html! {
780→                            <div style={bg.to_string()}>
781→                                <span style="color:#bac2de;">{&formatted[..addr_end]}</span>
782→                                <span style="color:#bac2de;">{&formatted[addr_end..hex_start]}</span>
783→                                <span style="color:#a6e3a1;">{&formatted[hex_start..hex_end.min(formatted.len())]}</span>
784→                                if formatted.len() > hex_end {
785→                                    <span style="color:#f9e2af;">{&formatted[hex_end..]}</span>
786→                                }
787→                            </div>
788→                        }
789→                    }
790→                }) }
791→            </pre>
792→        </div>
793→    }
794→}
