246→    /// Feed one byte from the UART RX queue if the UART is ready.
247→    fn feed_uart_byte(&mut self) {
248→        if self.uart_rx_queue.is_empty() {
249→            return;
250→        }
251→        let status = self.emulator.read_byte(0xFF0101);
252→        if status & 0x01 == 0
253→            && let Some(byte) = self.uart_rx_queue.pop_front()
254→        {
255→            self.emulator.send_uart_byte(byte);
256→        }
257→    }
