274→    /// Resolve an address to the nearest label at or before it.
275→    fn resolve_addr(&self, addr: u32) -> String {
276→        if let Some(name) = self.reverse_labels.get(&addr) {
277→            return name.clone();
278→        }
279→        // Find the closest label before this address.
280→        let mut best: Option<(&String, u32)> = None;
281→        for (name, &label_addr) in &self.labels {
282→            if label_addr <= addr {
283→                let dist = addr - label_addr;
284→                if dist < 32 {
285→                    match best {
286→                        None => best = Some((name, dist)),
287→                        Some((_, bd)) if dist < bd => best = Some((name, dist)),
288→                        _ => {}
289→                    }
290→                }
291→            }
292→        }
293→        match best {
294→            Some((name, 0)) => name.clone(),
295→            Some((name, offset)) => format!("{}+{}", name, offset),
296→            None => format!("{:06X}", addr),
297→        }
298→    }
299→
300→    /// Build categorized dictionary entries from assembler labels.
301→    fn build_dict_entries(&self) -> Vec<DictEntry> {
302→        let mut entries: Vec<DictEntry> = self
303→            .labels
304→            .iter()
305→            .filter_map(|(name, &addr)| {
306→                // Skip internal labels (tx1, halt_loop, emit_poll, etc.)
307→                if name.starts_with("tx")
308→                    || name.starts_with("halt_")
309→                    || name.starts_with("emit_")
310→                    || name.starts_with("key_")
311→                    || name.starts_with("zbr_")
312→                    || name.starts_with("eq_")
313→                    || name.starts_with("lt_")
314→                    || name.starts_with("zeq_")
315→                    || name == "_start"
316→                {
317→                    return None;
318→                }
319→
320→                let kind = if name.ends_with("_word") {
321→                    WordKind::ColonDef
322→                } else if name.ends_with("_thread") {
323→                    WordKind::Thread
324→                } else if name.starts_with("do_") {
325→                    WordKind::Primitive
326→                } else {
327→                    return None; // skip unrecognized
328→                };
329→
330→                Some(DictEntry {
331→                    name: name.clone(),
332→                    addr,
333→                    kind,
334→                })
335→            })
336→            .collect();
337→        entries.sort_by_key(|e| e.addr);
338→        entries
339→    }
340→
341→    /// Read the thread (parameter field) of a colon word starting at addr+3.
342→    fn read_word_thread(&self, cfa_addr: u32) -> Vec<(u32, String)> {
343→        let pfa = cfa_addr + CELL; // PFA = CFA + 3
344→        let mut thread = Vec::new();
345→        let mut addr = pfa;
346→        let mut next_is_literal = false;
347→
348→        for _ in 0..32 {
349→            let word_addr = self.emulator.read_word(addr) & 0xFFFFFF;
350→            if next_is_literal {
351→                // After do_lit / do_branch / do_zbranch, the next cell is a value, not a CFA
352→                thread.push((word_addr, format!("{}", word_addr)));
353→                next_is_literal = false;
354→            } else {
355→                let name = self.resolve_addr(word_addr);
356→                next_is_literal = name == "do_lit" || name == "do_branch" || name == "do_zbranch";
357→                thread.push((word_addr, name.clone()));
358→
359→                // Stop after do_exit or do_halt
360→                if name == "do_exit" || name == "do_halt" {
361→                    break;
362→                }
363→            }
364→            addr += CELL;
365→        }
366→        thread
367→    }
368→
369→    /// Build caller chain by walking the return stack and resolving addresses.
370→    fn build_caller_chain(&self) -> Vec<(u32, String)> {
371→        let rsp = self.emulator.snapshot().regs[1];
372→        let rstack_base: u32 = 0x0F0000;
373→        let mut chain = Vec::new();
374→        // Only walk when RSP has been initialized to the return stack region
375→        if rsp == 0 || rsp >= rstack_base {
376→            return chain;
377→        }
378→        let mut addr = rstack_base;
379→
380→        while addr > rsp && chain.len() < 16 {
381→            addr -= CELL;
382→            let ret_addr = self.emulator.read_word(addr) & 0xFFFFFF;
383→            // Return addresses point into a thread. Try to find which word's PFA this is in.
384→            let name = self.resolve_addr(ret_addr);
385→            chain.push((ret_addr, name));
386→        }
387→        chain.reverse();
388→        chain
389→    }
390→
391→    /// Compute memory regions for the visualization bar.
392→    fn memory_regions(&self) -> Vec<(&'static str, &'static str, u32)> {
393→        let rsp = self.emulator.snapshot().regs[1];
394→        let sp = self.emulator.snapshot().regs[4];
395→        let rstack_base: u32 = 0x0F0000;
396→        let stack_top = self.stack_size.initial_sp();
397→
398→        let kernel_end = self.program_end;
399→        let rstack_used = rstack_base.saturating_sub(rsp);

