451→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
452→        match msg {
453→            Msg::Init => {
454→                self.load_binary(ctx);
455→                true
456→            }
457→
458→            Msg::Tick => {
459→                if !self.running {
460→                    return false;
461→                }
462→
463→                self.prev_regs = self.snapshot_regs();
464→                self.prev_pc = self.emulator.snapshot().pc;
465→                self.feed_uart_byte();
466→
467→                let result = self.emulator.run_batch(BATCH_SIZE);
468→                self.collect_uart_output();
469→
470→                if self.emulator.is_halted() {
471→                    self.running = false;
472→                    self.halted = true;
473→                } else if matches!(result.reason, cor24_emulator::StopReason::Breakpoint(_)) {
474→                    self.running = false;
475→                    self.emulator.pause();
476→                } else if self.running {
477→                    self.schedule_tick(ctx);
478→                }
479→
480→                true
481→            }
482→
483→            Msg::InputChanged(val) => {
484→                self.input = val;
485→                false
486→            }
487→
488→            Msg::SendInput => {
489→                if self.input.is_empty() {
490→                    return false;
491→                }
492→                for b in self.input.bytes() {
493→                    self.uart_rx_queue.push_back(b);
494→                }
495→                self.uart_rx_queue.push_back(b'\n');
496→                self.input.clear();
497→
498→                if !self.running && !self.halted {
499→                    self.running = true;
500→                    self.emulator.resume();
501→                    self.schedule_tick(ctx);
502→                }
503→                true
504→            }
505→
506→            Msg::SetTier(tier) => {
507→                self.tier = tier;
508→                self.load_binary(ctx);
509→                true
510→            }
511→
512→            Msg::SetStack(size) => {
513→                self.stack_size = size;
514→                self.load_binary(ctx);
515→                true
516→            }
517→
518→            Msg::Reset => {
519→                self.load_binary(ctx);
520→                true
521→            }
522→
523→            Msg::Step => {
524→                if self.halted {
525→                    return false;
526→                }
527→                self.running = false;
528→                self.emulator.resume();
529→
530→                self.prev_regs = self.snapshot_regs();
531→                self.prev_pc = self.emulator.snapshot().pc;
532→
533→                self.feed_uart_byte();
534→                let _result = self.emulator.step();
535→                self.collect_uart_output();
536→
537→                self.emulator.pause();
538→                if self.emulator.is_halted() {
539→                    self.halted = true;
540→                }
541→                true
542→            }
543→
544→            Msg::StepOver => {
545→                if self.halted {
546→                    return false;
547→                }
548→                self.running = false;
549→                self.emulator.resume();
550→
551→                self.prev_regs = self.snapshot_regs();
552→                self.prev_pc = self.emulator.snapshot().pc;
553→
554→                self.feed_uart_byte();
555→                let _result = self.emulator.step_over();
556→                self.collect_uart_output();
557→
558→                self.emulator.pause();
559→                if self.emulator.is_halted() {
560→                    self.halted = true;
561→                }
562→                true
563→            }
564→
565→            Msg::PauseResume => {
566→                if self.halted {
567→                    return false;
568→                }
569→                if self.running {
570→                    self.running = false;
571→                    self.emulator.pause();
572→                    self._tick_handle = None;
573→                } else {
574→                    self.running = true;
575→                    self.emulator.resume();
576→                    self.schedule_tick(ctx);
577→                }
578→                true
579→            }
580→
581→            Msg::InputKeyDown(e) => {
582→                if e.key() == "Enter" {
583→                    ctx.link().send_message(Msg::SendInput);
584→                }
585→                false
586→            }
587→
588→            Msg::ToggleBreakpoint(addr) => {
589→                if self.emulator.has_breakpoint(addr) {
590→                    self.emulator.remove_breakpoint(addr);
591→                } else {
592→                    self.emulator.add_breakpoint(addr);
593→                }
594→                true
595→            }
596→
597→            Msg::LoadDemo(index) => {
598→                if let Some(demo) = DEMOS.get(index) {
599→                    self.selected_demo = Some(index);
600→                    // Switch tier if needed and reset
601→                    self.tier = demo.tier;
602→                    self.load_binary(ctx);
603→                    // Feed demo source line-by-line into UART
604→                    for line in demo.source.lines() {
605→                        let trimmed = line.trim();
606→                        // Skip empty lines and comments
607→                        if trimmed.is_empty() || trimmed.starts_with('\\') {
608→                            continue;
609→                        }
610→                        for b in trimmed.bytes() {
611→                            self.uart_rx_queue.push_back(b);
612→                        }
613→                        self.uart_rx_queue.push_back(b'\n');
614→                    }
615→                    // Auto-run
616→                    self.running = true;
617→                    self.emulator.resume();
618→                    self.schedule_tick(ctx);
619→                }
620→                true
621→            }
622→
623→            Msg::FileChanged(e) => {
624→                let input: HtmlInputElement = e.target_unchecked_into();
625→                if let Some(file_list) = input.files()
626→                    && let Some(file) = file_list.get(0)
627→                {
628→                    let file = File::from(file);
629→                    let link = ctx.link().clone();
630→                    let reader = gloo::file::callbacks::read_as_text(&file, move |result| {
631→                        if let Ok(text) = result {
632→                            link.send_message(Msg::LoadFile(text));
633→                        }
634→                    });
635→                    self._file_reader = Some(reader);
636→                }
637→                // Reset the input so the same file can be re-selected
638→                input.set_value("");
639→                false
640→            }
641→
642→            Msg::LoadFile(contents) => {
643→                self.selected_demo = None;
644→                // Ensure Interpreter tier
645→                if self.tier != ForthTier::Interpreter {
646→                    self.tier = ForthTier::Interpreter;
647→                }
648→                self.load_binary(ctx);
649→                // Feed file contents line-by-line into UART
650→                for line in contents.lines() {
651→                    let trimmed = line.trim();
652→                    if trimmed.is_empty() || trimmed.starts_with('\\') {
653→                        continue;
654→                    }
655→                    for b in trimmed.bytes() {
656→                        self.uart_rx_queue.push_back(b);
657→                    }
658→                    self.uart_rx_queue.push_back(b'\n');
659→                }
660→                // Auto-run
661→                self.running = true;
662→                self.emulator.resume();
663→                self.schedule_tick(ctx);
664→                true
665→            }
666→
667→            Msg::ToggleSwitch => {
668→                self.switch_pressed = !self.switch_pressed;
669→                self.emulator.set_button_pressed(self.switch_pressed);
670→                true
671→            }
672→
673→            Msg::SelectWord(name) => {
674→                if self.selected_word.as_ref() == Some(&name) {
675→                    self.selected_word = None; // toggle off
676→                } else {
677→                    self.selected_word = Some(name);
678→                }
679→                true
680→            }
681→
682→            Msg::SetBottomTab(tab) => {
683→                self.bottom_tab = tab;
684→                true
685→            }
686→        }
687→    }
